import sys

def can_be_obtained(s1: str, s2: str) -> bool:
    """Return True iff a substitution cipher (bijection) can turn s1 into s2."""
    if len(s1) != len(s2):
        return False

    forward = {}
    backward = {}

    for c1, c2 in zip(s1, s2):
        # forward consistency
        if c1 in forward:
            if forward[c1] != c2:
                return False
        else:
            forward[c1] = c2

        # backward consistency (injectivity)
        if c2 in backward:
            if backward[c2] != c1:
                return False
        else:
            backward[c2] = c1

    return True


